SELECT COUNT(*) AS QUANTIDADE FROM LATTES_P_PRODBIB LPB JOIN LATTES_PRODBIB PB ON LPB.FK_PRODBIB = PB.PK JOIN SERVIDOR S ON LPB.FK_SIAPE = S.PK_SIAPE WHERE LOWER(PB.NATUREZA) = LOWER('RESUMO') AND LOWER(PB.TIPO) LIKE LOWER('%TRABALHO%') AND LOWER(S.CAMPUS_ATUAL) LIKE LOWER('%formosa%') AND LOWER(S.AREA_INGRESSO) LIKE LOWER('%biologia geral%') AND PB.ANO = '2023'